// 粒子系统 Compute Shader
struct Particle {
    position: vec3<f32>,
    velocity: vec3<f32>,
    life: f32,
    color: vec4<f32>,
};

struct SimParams {
    deltaTime: f32,
    gravity: vec3<f32>,
    particleCount: u32,
};

@group(0) @binding(0) var<uniform> params: SimParams;
@group(0) @binding(1) var<storage, read_write> particles: array<Particle>;

@compute @workgroup_size(64)
fn main(@builtin(global_invocation_id) id: vec3<u32>) {
    let index = id.x;
    if (index >= params.particleCount) {
        return;
    }

    var p = particles[index];

    // 应用重力
    p.velocity += params.gravity * params.deltaTime;

    // 更新位置
    p.position += p.velocity * params.deltaTime;

    // 减少生命值
    p.life -= params.deltaTime;

    // 边界检测
    if (p.position.y < 0.0) {
        p.position.y = 0.0;
        p.velocity.y = -p.velocity.y * 0.8;  // 反弹
    }

    particles[index] = p;
}

// WebGPU 计算管线创建
const computePipeline = device.createComputePipeline({
    layout: device.createPipelineLayout({
        bindGroupLayouts: [bindGroupLayout],
    }),
    compute: {
        module: computeShaderModule,
        entryPoint: 'main',
    },
});

// 计算命令录制流程
const encoder = device.createCommandEncoder();
const computePass = encoder.beginComputePass();

// 绑定计算管线和资源
computePass.setPipeline(computePipeline);
computePass.setBindGroup(0, computeBindGroup);

// 启动计算：100 个工作组，每组 64 线程
computePass.dispatchWorkgroups(100, 1, 1);

computePass.end();

// 提交命令
const commandBuffer = encoder.finish();
device.queue.submit([commandBuffer]);

// 创建 Storage Buffer
const particleBuffer = device.createBuffer({
    size: particleCount * PARTICLE_STRIDE,
    usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST,
    mappedAtCreation: true,
});

// 初始化数据
const data = new Float32Array(particleBuffer.getMappedRange());
for (let i = 0; i < particleCount; i++) {
    data[i * 8 + 0] = Math.random() * 10 - 5;  // position.x
    data[i * 8 + 1] = Math.random() * 10;       // position.y
    data[i * 8 + 2] = Math.random() * 10 - 5;  // position.z
    data[i * 8 + 3] = 0;                         // padding
    data[i * 8 + 4] = (Math.random() - 0.5) * 2; // velocity.x
    data[i * 8 + 5] = Math.random() * 5;         // velocity.y
    data[i * 8 + 6] = (Math.random() - 0.5) * 2; // velocity.z
    data[i * 8 + 7] = 1.0;                        // life
}
particleBuffer.unmap();

// 每帧的计算更新
const encoder = device.createCommandEncoder();

// 计算 Pass：更新粒子
const computePass = encoder.beginComputePass();
computePass.setPipeline(computePipeline);
computePass.setBindGroup(0, computeBindGroup);
computePass.dispatchWorkgroups(Math.ceil(particleCount / 64), 1, 1);
computePass.end();

// 渲染 Pass：绘制粒子
const renderPass = encoder.beginRenderPass(renderPassDescriptor);
renderPass.setPipeline(renderPipeline);
renderPass.setBindGroup(0, renderBindGroup);
renderPass.setVertexBuffer(0, particleBuffer);  // 同一个 Buffer！
renderPass.draw(6, particleCount);  // 每个粒子 6 个顶点（四边形）
renderPass.end();

// 完整的 WebGPU 渲染一帧的流程

// 1. 获取当前纹理（从交换链）
const textureView = context.getCurrentTexture().createView();

// 2. 创建命令编码器
const encoder = device.createCommandEncoder();

// 3. （可选）执行计算 Pass
const computePass = encoder.beginComputePass();
// ... 录制计算命令
computePass.end();

// 4. 执行渲染 Pass
const renderPass = encoder.beginRenderPass({
    colorAttachments: [{
        view: textureView,
        clearValue: { r: 0, g: 0, b: 0, a: 1 },
        loadOp: 'clear',
        storeOp: 'store',
    }],
});
// ... 录制渲染命令
renderPass.end();

// 5. 完成命令编码
const commandBuffer = encoder.finish();

// 6. 提交到队列
device.queue.submit([commandBuffer]);

